mapper.select:
select
    register_time as registerTime,
    agent_type as agentType,
    agent_account as agentAccount,
    register_ip as registerIp,
    registrant as registrant,
    register_ip_control_id as registerIpControlId,
    ip_attribution as ipAttribution,
    register_device as registerDevice,
    device_control_id as deviceControlId,
    device_number as deviceNumber
    from agent_register_info
where 1 = 1

    AND site_code = #{vo.siteCode}


    AND agent_type = #{vo.agentType}


    AND agent_account = #{vo.agentAccount}


    AND register_ip = #{vo.registerIp}


    AND ip_attribution = #{vo.ipAttribution}


    AND register_device = #{vo.registerDevice}


    AND register_time  >=  #{vo.startTime}


    AND register_time  <=  #{vo.endTime}




        ORDER BY registerTime asc


        ORDER BY registerTime desc



        order by register_time desc , register_ip desc
